create table public.people (  id uuid primary key default gen_random_uuid(),  tenant_id uuid not null references public.tenants(id) on delete cascade,  external_person_id text,  name text not null,  email text not null,  department text,  job_title text,  manager_person_id uuid references public.people(id) on delete set null,  metadata_json jsonb,  created_at timestamptz not null default now(),  unique (tenant_id, email));create table public.assessment_cycles (  id uuid primary key default gen_random_uuid(),  tenant_id uuid not null references public.tenants(id) on delete cascade,  template_id uuid not null references public.assessment_templates(id),  name text not null,  status text not null default 'draft' check (status in ('draft','active','closed','archived')),  start_at timestamptz,  deadline_at timestamptz,  report_release_at timestamptz,  settings_override_json jsonb,  template_snapshot_json jsonb,  created_by uuid references public.users(id),  created_at timestamptz not null default now());create index on public.assessment_cycles (tenant_id, status);create table public.cycle_participants (  id uuid primary key default gen_random_uuid(),  tenant_id uuid not null references public.tenants(id) on delete cascade,  cycle_id uuid not null references public.assessment_cycles(id) on delete cascade,  person_id uuid not null references public.people(id),  manager_person_id uuid references public.people(id),  metadata_json jsonb,  created_at timestamptz not null default now(),  unique (cycle_id, person_id));create index on public.cycle_participants (tenant_id, cycle_id);